import json

def calculate_average_effectiveness(feedback, treatment_name):
    """
    Calculate the average effectiveness of a specified treatment across all patients who provided feedback for it.

    Parameters:
    - feedback (list of dict): A list of dictionaries where each dictionary represents a patient's feedback.
                               Each dictionary has "name" and "treatments" keys. "treatments" is a dictionary
                               mapping treatment names to effectiveness ratings (integers from 1 to 10).
    - treatment_name (str): The name of the treatment for which to calculate the average effectiveness.

    Returns:
    - float: The average effectiveness of the specified treatment, rounded to two decimal places.
             If no patient provided feedback for the treatment, returns 0.0.

    Example:
    >>> feedback = [
    ...     {"name": "Alice", "treatments": {"Yoga": 7, "Meditation": 8}},
    ...     {"name": "Bob", "treatments": {"Yoga": 5, "Art Therapy": 6}},
    ...     {"name": "Charlie", "treatments": {"Meditation": 9, "Art Therapy": 8}}
    ... ]
    >>> calculate_average_effectiveness(feedback, "Yoga")
    6.0
    """
    total_effectiveness = 0
    count = 0

    for patient in feedback:
        if treatment_name in patient["treatments"]:
            total_effectiveness += patient["treatments"][treatment_name]
            count += 1

    if count == 0:
        return 0.0
    else:
        average = total_effectiveness / count
        return round(average, 2)

